# scripts/quarterly_internal_audit.py
# Samples control evidence from S3 for the quarter and generates an audit workpaper

import boto3, json, datetime, random

s3 = boto3.client("s3")
BUCKET = "my-company-compliance-evidence"

def list_evidence_for_control(control_id: str, year_month: str) -> list[str]:
    prefix = f"evidence/{control_id}/{year_month}/"
    resp = s3.list_objects_v2(Bucket=BUCKET, Prefix=prefix)
    return [obj["Key"] for obj in resp.get("Contents", [])]

def sample_evidence(control_id: str, months: list[str], n: int = 15) -> list[dict]:
    all_keys = []
    for ym in months:
        all_keys.extend(list_evidence_for_control(control_id, ym))
    sample_keys = random.sample(all_keys, min(n, len(all_keys)))
    records = []
    for key in sample_keys:
        obj = s3.get_object(Bucket=BUCKET, Key=key)
        records.append(json.loads(obj["Body"].read()))
    return records

def run_quarterly_audit(quarter_months: list[str], controls: list[str]) -> dict:
    results = {}
    for ctrl in controls:
        sample = sample_evidence(ctrl, quarter_months)
        results[ctrl] = {
            "population_size": sum(
                len(list_evidence_for_control(ctrl, m)) for m in quarter_months
            ),
            "sample_size": len(sample),
            "all_have_sha256": all("sha256" in r for r in sample),
            "findings": [],  # populated by auditor review
        }
    return results

# Q1 2026 example
if __name__ == "__main__":
    report = run_quarterly_audit(
        quarter_months=["2026-01", "2026-02", "2026-03"],
        controls=["CC6.1", "CC6.2", "CC8.1"],
    )
    print(json.dumps(report, indent=2))

# compliance_calendar.py — emit alerts for upcoming certification events

import json, datetime

CERTIFICATIONS = [
    {"name": "SOC 2 Type II", "expiry": "2026-12-31", "alert_days": 60},
    {"name": "ISO 42001 Certificate", "expiry": "2027-10-15", "alert_days": 180},
    {"name": "ISO 27001 Certificate", "expiry": "2027-10-15", "alert_days": 180},
    {"name": "ISO 42001 Surveillance Y1", "expiry": "2025-10-15", "alert_days": 90},
    {"name": "Anthropic DPA Renewal", "expiry": "2026-06-30", "alert_days": 90},
]

def check_upcoming_events(today: datetime.date = None) -> list[dict]:
    today = today or datetime.date.today()
    alerts = []
    for cert in CERTIFICATIONS:
        expiry = datetime.date.fromisoformat(cert["expiry"])
        days_until = (expiry - today).days
        if days_until <= cert["alert_days"]:
            alerts.append({
                "certification": cert["name"],
                "expiry": cert["expiry"],
                "days_until_expiry": days_until,
                "urgency": "critical" if days_until <= 30 else "warning",
            })
    return sorted(alerts, key=lambda a: a["days_until_expiry"])

if __name__ == "__main__":
    alerts = check_upcoming_events()
    if alerts:
        print("COMPLIANCE CALENDAR ALERTS:")
        for a in alerts:
            print(f"  [{a['urgency'].upper()}] {a['certification']} expires {a['expiry']} ({a['days_until_expiry']} days)")
    else:
        print("No upcoming certification events within alert windows.")
